module parallel_register(
    input clk,
    input clear_n,
    input [63:0] data_in,
    output reg [63:0] data_out
    );
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (!clear_n)
            data_out <= 64'b0;
        else
            data_out <= data_in;
    end
endmodule
